using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides a web search tool that queries a public search API and returns results.
/// Uses the Brave Search API when a key is configured, otherwise falls back to
/// DuckDuckGo Instant Answer for zero-config demo usage.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;
    private readonly string? _braveApiKey;

    public WebSearchTool(HttpClient httpClient, string? braveApiKey = null)
    {
        _httpClient = httpClient;
        _braveApiKey = braveApiKey;
    }

    [Description("Search the web for information on a given query. Returns a list of results with titles, URLs, and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            if (!string.IsNullOrEmpty(_braveApiKey))
            {
                return await SearchWithBraveAsync(query, maxResults);
            }

            return await SearchWithDuckDuckGoAsync(query);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. The agent should inform the user and try rephrasing the query.";
        }
    }

    private async Task<string> SearchWithBraveAsync(string query, int maxResults)
    {
        var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count={maxResults}");
        request.Headers.Add("X-Subscription-Token", _braveApiKey);
        request.Headers.Add("Accept", "application/json");

        var response = await _httpClient.SendAsync(request);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync();
        using var doc = JsonDocument.Parse(json);

        var results = new List<string>();
        if (doc.RootElement.TryGetProperty("web", out var web) &&
            web.TryGetProperty("results", out var webResults))
        {
            foreach (var result in webResults.EnumerateArray().Take(maxResults))
            {
                var title = result.GetProperty("title").GetString();
                var url = result.GetProperty("url").GetString();
                var description = result.TryGetProperty("description", out var desc)
                    ? desc.GetString() : "No description";
                results.Add($"- **{title}**\n  URL: {url}\n  {description}");
            }
        }

        return results.Count > 0
            ? $"Found {results.Count} results for \"{query}\":\n\n{string.Join("\n\n", results)}"
            : $"No results found for \"{query}\".";
    }

    private async Task<string> SearchWithDuckDuckGoAsync(string query)
    {
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";
        var response = await _httpClient.GetStringAsync(url);
        using var doc = JsonDocument.Parse(response);

        var results = new List<string>();

        if (doc.RootElement.TryGetProperty("Abstract", out var abs) &&
            abs.GetString() is { Length: > 0 } abstractText)
        {
            var source = doc.RootElement.TryGetProperty("AbstractSource", out var src) ? src.GetString() : "Unknown";
            var absUrl = doc.RootElement.TryGetProperty("AbstractURL", out var au) ? au.GetString() : "";
            results.Add($"- **{source} Summary**\n  URL: {absUrl}\n  {abstractText}");
        }

        if (doc.RootElement.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(5))
            {
                if (topic.TryGetProperty("Text", out var text) &&
                    topic.TryGetProperty("FirstURL", out var firstUrl))
                {
                    results.Add($"- {text.GetString()}\n  URL: {firstUrl.GetString()}");
                }
            }
        }

        return results.Count > 0
            ? $"Found {results.Count} results for \"{query}\":\n\n{string.Join("\n\n", results)}"
            : $"No detailed results found for \"{query}\". Try a more specific or different query.";
    }
}

