toolArgs.new_str:
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";
var braveApiKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY"); // optional

// --- Tool instances ---
var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var webSearch = new WebSearchTool(httpClient, braveApiKey);
var noteTaking = new NoteTakingTool();

// --- Build the chat client with function-calling support ---
IChatClient chatClient = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// --- Create the agent with tools ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. Your job is to research a topic thoroughly using web searches,
        take organized notes on your findings, and then produce a comprehensive summary.

        Follow this process:
        1. Break the topic into 2-4 key subtopics or questions to investigate.
        2. Search the web for each subtopic. Try different queries if initial results are sparse.
        3. For each useful finding, save a note with a descriptive topic tag, the key information, and the source URL.
        4. After gathering enough information, review all your notes.
        5. Produce a well-structured summary with sections, citing your sources.

        Be thorough but concise. Focus on factual, well-sourced information.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools:
    [
        AIFunctionFactory.Create(webSearch.SearchWebAsync),
        AIFunctionFactory.Create(noteTaking.AddNote),
        AIFunctionFactory.Create(noteTaking.GetNotes),
    ]);

// --- Get the research topic ---
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent               ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
    Console.WriteLine($"Researching: {topic}");
}
else
{
    Console.Write("Enter a topic to research: ");
    topic = Console.ReadLine()?.Trim() ?? "";
    if (string.IsNullOrWhiteSpace(topic))
    {
        Console.WriteLine("No topic provided. Exiting.");
        return;
    }
}

Console.WriteLine();
Console.ForegroundColor = ConsoleColor.DarkGray;
Console.WriteLine("Researching... (the agent will search the web and take notes)");
Console.ResetColor();
Console.WriteLine();

// --- Run the agent ---
var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

AgentResponse response;
try
{
    response = await agent.RunAsync(
        $"Please research the following topic and provide a comprehensive summary:\n\n{topic}",
        session,
        runOptions);
}
catch (Exception ex)
{
    Console.ForegroundColor = ConsoleColor.Red;
    Console.WriteLine($"Agent error: {ex.Message}");
    Console.ResetColor();
    return;
}

// --- Display results ---
Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine("═══ Research Summary ═══");
Console.ResetColor();
Console.WriteLine();
Console.WriteLine(response.Text);

// Show collected notes
if (noteTaking.Notes.Count > 0)
{
    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Yellow;
    Console.WriteLine($"═══ Research Notes ({noteTaking.Notes.Count} collected) ═══");
    Console.ResetColor();
    foreach (var note in noteTaking.Notes)
    {
        Console.WriteLine($"  [{note.Topic}] {note.Content[..Math.Min(note.Content.Length, 120)]}...");
        if (note.SourceUrl is not null)
            Console.WriteLine($"    Source: {note.SourceUrl}");
    }
}

// Show token usage if available
if (response.Usage is { } usage)
{
    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"Tokens — Input: {usage.InputTokenCount}, Output: {usage.OutputTokenCount}, Total: {usage.TotalTokenCount}");
    Console.ResetColor();
}

